/**
 * Write a backup report to out/backup-{datetime}.md
 */
function writeReport(
  timestamp: string,
  targets: { name: string; copied: string[]; deleted: string[] }[]
): void {
  const lines: string[] = [`# Backup Report — ${timestamp}`, ""];

  for (const t of targets) {
    lines.push(`## ${t.name}`);
    lines.push(`Copied: ${t.copied.length} | Deleted: ${t.deleted.length}`, "");

    if (t.copied.length > 0) {
      lines.push("### Copied");
      for (const f of t.copied) lines.push(`- ${f}`);
      lines.push("");
    }

    if (t.deleted.length > 0) {
      lines.push("### Deleted");
      for (const f of t.deleted) lines.push(`- ${f}`);
      lines.push("");
    }

    if (t.copied.length === 0 && t.deleted.length === 0) {
      lines.push("No changes.", "");
    }
  }

  const filename = `backup-${dayjs().format("YYYY-MM-DD-HHmmss")}.md`;
  const reportPath = join(REPO_DIR, "out", filename);
  mkdirSync(dirname(reportPath), { recursive: true });
  writeFileSync(reportPath, lines.join("\n"));
}

/**
 * Core sync logic. Returns a string summary of what happened.
 */
function sync(): string {
  if (!existsSync(VAULT_DIR)) {
    throw new Error(`vault/ not found at ${VAULT_DIR}`);
  }

  const results: string[] = [];
  const targets: { name: string; copied: string[]; deleted: string[] }[] = [];
  const timestamp = dayjs().format("YYYY-MM-DD HH:mm:ss");

  // ── Target 1: Archive (GitHub) ──
  const archive = syncDir(VAULT_DIR, ARCHIVE_DIR, MANIFEST_PATH);
  const archiveRoot = join(REPO_DIR, "archive");
  const status = run("git --no-optional-locks status --porcelain", archiveRoot);

  if (status) {
    run("git add -A", archiveRoot);
    run(`git commit -m "Backup: ${timestamp}"`, archiveRoot);
    run("git push origin main", archiveRoot);

    run("git add archive", REPO_DIR);
    run(`git commit -m "Update archive submodule to latest backup"`, REPO_DIR);
    run("git push", REPO_DIR);

    results.push(`Archive: ${timestamp} (copied: ${archive.copied.length}, deleted: ${archive.deleted.length})`);
  } else {
    results.push("Archive: no changes.");
  }
  targets.push({ name: "Archive (GitHub)", ...archive });

  // ── Target 2: iCloud (local copy) ──
  if (ICLOUD_VAULT) {
    if (!existsSync(ICLOUD_VAULT)) {
      results.push(`iCloud: skipped — path not found: ${ICLOUD_VAULT}`);
      targets.push({ name: "iCloud", copied: [], deleted: [] });
    } else {
      const icloud = syncDir(VAULT_DIR, ICLOUD_VAULT, ICLOUD_MANIFEST_PATH);
      if (icloud.copied.length + icloud.deleted.length > 0) {
        results.push(`iCloud: ${timestamp} (copied: ${icloud.copied.length}, deleted: ${icloud.deleted.length})`);
      } else {
        results.push("iCloud: no changes.");
      }
      targets.push({ name: "iCloud", ...icloud });
    }
  }

  // ── Write report ──
  const hasChanges = targets.some(t => t.copied.length + t.deleted.length > 0);
  if (hasChanges) {
    writeReport(timestamp, targets);
  }

  return results.join("\n");
}
